export const name = "repo";
export const version = "0.1.0";
export const description = "";

export function getIdentity() {
  return { name, version, description };
}

export function slugify(input) {
  const s = toStr(input);
  if (!s) return "";
  // Normalize and remove diacritics
  let t = s.normalize("NFKD").replace(/[\u0300-\u036f]/g, "");
  t = t.toLowerCase();
  // Replace non alphanumeric sequences with hyphen
  t = t.replace(/[^\p{L}\p{N}]+/gu, "-");
  // Trim leading/trailing hyphens
  t = t.replace(/^-+|-+$/g, "");
  return t;
}

export function truncate(input, maxLength = 0, suffix = "…") {
  const s = toStr(input);
  if (!s) return "";
  maxLength = Number(maxLength) || 0;
  const suffixStr = toStr(suffix);
  const suflen = [...suffixStr].length;
  // If string fits or invalid maxLength, return original
  const chars = [...s];
  if (maxLength <= 0 || chars.length <= maxLength) return s;
  const allowed = maxLength - suflen;
  if (allowed <= 0) return suffixStr;
  const cut = chars.slice(0, allowed).join("");
  const lastSpace = cut.lastIndexOf(" ");
  if (lastSpace > 0) {
    return cut.slice(0, lastSpace) + suffixStr;
  }
  return cut + suffixStr;
}

export function camelCase(input) {
  const words = splitWords(input);
  if (!words.length) return "";
  const first = words[0].toLowerCase();
  const rest = words
    .slice(1)
    .map((w) => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase())
    .join("");
  return first + rest;
}

export function kebabCase(input) {
  const words = splitWords(input);
  if (!words.length) return "";
  return words.map((w) => w.toLowerCase()).join("-");
}

export function titleCase(input) {
  const words = splitWords(input);
  if (!words.length) return "";
  return words
    .map((w) => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase())
    .join(" ");
}

export function wordWrap(input, width = 80) {
  const s = toStr(input);
  if (!s) return "";
  width = Math.max(1, Number(width) || 0);
  const words = s.split(/\s+/);
  const lines = [];
  let current = "";
  for (const w of words) {
    if (!current) {
      if ([...w].length > width) {
        // Single long word on its own line
        lines.push(w);
      } else {
        current = w;
      }
    } else {
      const candidate = current + " " + w;
      if ([...candidate].length <= width) {
        current = candidate;
      } else {
        lines.push(current);
        if ([...w].length > width) {
          lines.push(w);
          current = "";
        } else {
          current = w;
        }
      }
    }
  }
  if (current) lines.push(current);
  return lines.join("\n");
}

export function stripHtml(input) {
  const s = toStr(input);
  if (!s) return "";
  // Remove tags
  let t = s.replace(/<[^>]*>/g, "");
  // Decode common named entities and numeric entities
  const named = { '&amp;': '&', '&lt;': '<', '&gt;': '>', '&quot;': '"', '&#39;': "'", '&nbsp;': ' ' };
  t = t.replace(/&[a-zA-Z]+;|&#\d+;|&#x[0-9a-fA-F]+;/g, (m) => {
    if (named[m]) return named[m];
    if (m.startsWith('&#x')) {
      const code = parseInt(m.slice(3, -1), 16);
      return String.fromCodePoint(code);
    }
    if (m.startsWith('&#')) {
      const code = parseInt(m.slice(2, -1), 10);
      return String.fromCodePoint(code);
    }
    return m;
  });
  return t;
}

export function escapeRegex(input) {
  const s = toStr(input);
  if (!s) return "";
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

export function pluralize(input) {
  const s = toStr(input);
  if (!s) return "";
  const lower = s.toLowerCase();
  if (/(s|x|z|ch|sh)$/i.test(lower)) return s + "es";
  if (/[^aeiou]y$/i.test(lower)) return s.slice(0, -1) + "ies";
  if (/(?:fe|f)$/i.test(lower)) return s.replace(/(?:fe|f)$/i, "ves");
  return s + "s";
}

export function levenshteinDistance(aInput, bInput) {
  const a = toStr(aInput);
  const b = toStr(bInput);
  const A = [...a];
  const B = [...b];
  const m = A.length;
  const n = B.length;
  if (m === 0) return n;
  if (n === 0) return m;
  let prev = new Array(n + 1);
  for (let j = 0; j <= n; j++) prev[j] = j;
  for (let i = 1; i <= m; i++) {
    const curr = [i];
    for (let j = 1; j <= n; j++) {
      const cost = A[i - 1] === B[j - 1] ? 0 : 1;
      curr[j] = Math.min(curr[j - 1] + 1, prev[j] + 1, prev[j - 1] + cost);
    }
    prev = curr;
  }
  return prev[n];
}
